-- SCHEMA SETUP FOR WEB_TOUR1
ALTER SESSION SET "_ORACLE_SCRIPT"=true;

-- Bảng Tours
CREATE TABLE "Tours" (
    "Id" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL,
    "Destination" NVARCHAR2(2000),
    "DurationDays" NUMBER(10) NOT NULL,
    "DurationNights" NUMBER(10) NOT NULL,
    "Attractions" NVARCHAR2(2000),
    "PriceIndividual" NUMBER(18,2) NOT NULL,
    "PriceGroup" NUMBER(18,2) NOT NULL,
    CONSTRAINT "PK_Tours" PRIMARY KEY ("Id")
);

-- Bảng BOOKINGS
CREATE TABLE "BOOKINGS" (
    "ID" NUMBER(10) GENERATED BY DEFAULT AS IDENTITY MINVALUE 1 MAXVALUE 9999999999999999999999999999 INCREMENT BY 1 START WITH 1 CACHE 20 NOORDER  NOCYCLE  NOKEEP  NOSCALE  NOT NULL,
    "TOUR_ID" NUMBER(10) NOT NULL,
    "NUMBER_OF_PEOPLE" NUMBER(10) NOT NULL,
    "IS_GROUP" NUMBER(10) NOT NULL,
    "TOTAL_PRICE" NUMBER(18,2) NOT NULL,
    "CUSTOMER_NAME" NVARCHAR2(2000),
    "CUSTOMER_EMAIL" NVARCHAR2(2000),
    "BOOKING_DATE" TIMESTAMP(7) NOT NULL,
    CONSTRAINT "PK_BOOKINGS" PRIMARY KEY ("ID"),
    CONSTRAINT "FK_BOOKINGS_Tours_TOUR_ID" FOREIGN KEY ("TOUR_ID") REFERENCES "Tours" ("Id") ON DELETE CASCADE
);

CREATE INDEX "IX_BOOKINGS_TOUR_ID" ON "BOOKINGS" ("TOUR_ID");

EXIT;
